<?php
namespace App\Domain\Shops;
use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Character;use App\Models\Shop;use App\Models\ShopOffer;use Carbon\CarbonImmutable;
final class ShopAvailabilityService{private $validator;public function __construct(ShopCatalogValidator $validator){$this->validator=$validator;}public function isShopVisible(Shop $shop,CarbonImmutable $now){$this->validator->validateShop($shop);return$shop->status===CatalogStatus::ACTIVE&&$shop->npc&&$shop->npc->status===CatalogStatus::ACTIVE&&$this->inside($shop->starts_at,$shop->ends_at,$now);}public function isOfferVisible(ShopOffer $offer,CarbonImmutable $now){$this->validator->validateOffer($offer);return$offer->visibility===ShopOfferVisibility::VISIBLE&&$this->isShopVisible($offer->shop,$now);}public function isOfferPurchasable(ShopOffer $offer,CarbonImmutable $now,Character $character=null){if(!$this->isOfferVisible($offer,$now)||$offer->status!==CatalogStatus::ACTIVE||!$this->inside($offer->starts_at,$offer->ends_at,$now)||($offer->stock_remaining!==null&&(int)$offer->stock_remaining===0)||$offer->item->status!==CatalogStatus::ACTIVE)return false;if($character!==null&&$offer->required_character_level!==null&&(int)$character->level<(int)$offer->required_character_level)return false;return true;}private function inside($starts,$ends,CarbonImmutable $now){return($starts===null||$now->gte($starts))&&($ends===null||$now->lt($ends));}}
